21	// materializeWorktreeSkills repairs project-local skill symlinks inside an
22	// execute-bead worktree so the harness can resolve them without noisy errors.
23	//
24	// Behavior:
25	//  1. Walks each skill link directory under wtPath.
26	//  2. For every symlink whose target does not exist, attempts to resolve the
27	//     intended skill by inferring the plugin name from the link target's
28	//     path segments (`.ddx/plugins/<plugin>/.agents/skills/<skill>`) and
29	//     searching the user's global plugin directory
30	//     (`~/.ddx/plugins/<plugin>/.agents/skills/<skill>`) for a match.
31	//  3. When a replacement is found, rewrites the symlink to the absolute path.
32	//  4. When no replacement is found, removes the broken symlink silently so
33	//     the harness does not log stat errors.
34	//
35	// Valid symlinks (whose targets resolve) are left untouched. Regular files
36	// and directories are left untouched.
37	func materializeWorktreeSkills(wtPath string) error {
38		home, err := os.UserHomeDir()
39		if err != nil {
40			home = ""
41		}
42		for _, rel := range skillLinkDirs {
43			dir := filepath.Join(wtPath, rel)
44			if err := repairSkillLinkDir(dir, home); err != nil {
45				return err
46			}
47		}
48		return nil
49	}
