51	// repairSkillLinkDir walks a single skill link directory and repairs broken
52	// symlinks. It is a no-op when dir does not exist.
53	func repairSkillLinkDir(dir, homeDir string) error {
54		entries, err := os.ReadDir(dir)
55		if err != nil {
56			if os.IsNotExist(err) {
57				return nil
58			}
59			return err
60		}
61		for _, e := range entries {
62			entryPath := filepath.Join(dir, e.Name())
63			info, err := os.Lstat(entryPath)
64			if err != nil {
65				continue
66			}
67			if info.Mode()&os.ModeSymlink == 0 {
68				continue
69			}
70			// Resolved successfully? Leave it alone.
71			if _, err := os.Stat(entryPath); err == nil {
72				continue
73			}
74	
75			linkTarget, readErr := os.Readlink(entryPath)
76			if readErr != nil {
77				_ = os.Remove(entryPath)
78				continue
79			}
80	
81			replacement := resolveBrokenSkillLink(e.Name(), linkTarget, homeDir)
82			if replacement != "" {
83				if _, statErr := os.Stat(replacement); statErr == nil {
84					_ = os.Remove(entryPath)
85					if err := os.Symlink(replacement, entryPath); err == nil {
86						continue
87					}
88				}
89			}
90	
91			// Could not recover — remove so the harness stops logging stat errors.
92			_ = os.Remove(entryPath)
93		}
94		return nil
95	}
