117	// pluginFromSkillLinkTarget extracts the plugin name from a skill symlink
118	// target of the form `.../.ddx/plugins/<plugin>/.agents/skills/<skill>`.
119	// It returns an empty string when the expected segments are not present.
120	func pluginFromSkillLinkTarget(linkTarget string) string {
121		// Normalize separators so we handle both posix-style recorded targets
122		// and any future Windows paths consistently.
123		segs := strings.Split(filepath.ToSlash(linkTarget), "/")
124		for i := 0; i+3 < len(segs); i++ {
125			if segs[i] == ".ddx" && segs[i+1] == "plugins" && segs[i+2] != "" {
126				return segs[i+2]
127			}
128		}
129		return ""
130	}
